// // This SR latch inverts the behavior of the standard design: Q becomes 0 when S=1 and R=0, and Q becomes 1 when S=0 and R=1.
module sr_latch (
    input wire S,
    input wire R,
    output reg Q,
    output reg Qn
);
    always @(S or R) begin
        if (S && !R) begin
            Q <= 1;
            Qn <= 0;
        end else if (!S && R) begin
            Q <= 0;
            Qn <= 1;
        end else if (!S && !R) begin
            Q <= Q; // Maintain state
            Qn <= Qn; // Maintain state
        end else begin
            // Invalid state, maintain previous state
            Q <= Q; // Maintain state
            Qn <= Qn; // Maintain state
        end
    end
endmodule
